import { Button, Card, CardContent, CardHeader, Container, Dialog, DialogContent, DialogTitle, Grid, List, ListItem, makeStyles, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'



const useStyle = makeStyles(theme => {
    return {
        title: {
            textAlign: 'center',
            color: '#fefefe'
        },
        answers: {
            border: '1px solid #999',
            borderRadius: '7px',
            marginBottom: theme.spacing(1)
        },
        dialog: {
            backgroundColor: '#162276'
        }
    }
})

const choices = [
    {
        questionOne: 'Sino ang taong mahal na mahal mo na sobrang pogi at mabait pa? <b /> Clue: Hindi siya pasaway.',
        answerChoice: [
            {answer: 'Phil', validation: true},
            {answer: 'Philip', validation: false},
            {answer: 'Babi', validation: true},
            {answer: 'Bal', validation: true}
        ]
    },
    
]

export default function Quiz() {
    const classes = useStyle()
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    }
    const closeQuiz = () => {
        setQuiz(false)
    }

    const number = 1
    const name = `Quiz ${number}/5`

    return (
        <div className={classes.root}>
            <Button variant='contained' color='secondary' onClick={openQuiz}>
                Open Dialog
            </Button>
            <Dialog classes={{paper: classes.dialog}} open={quiz} onClose={closeQuiz} fullScreen>
                <Typography variant='h4' className={classes.title}>Boyfriend Check</Typography>
                <DialogContent>
                    <Card elevation={20} >
                        <Container>
                            <CardHeader title={name} subheader='Pag nasagot mo maganda ka.' />
                            <CardContent>
                                <Grid container spacing={1}>
                                    
                                    <Grid item xs={12}>
                                        <Typography>
                                            {choices[0].questionOne}
                                        </Typography>
                                    </Grid>
                                    

                                    <Grid item xs={12}>
                                        <List>
                                            {choices.map(choice => (
                                                <ListItem button className={classes.answers} >{choice[0].answerChoice[0]}</ListItem>
                                            ))}
                                        </List>
                                    </Grid>

                                </Grid>
                            </CardContent>
                        </Container>
                    </Card>
                </DialogContent>
            </Dialog>
        </div>
    )
}
